import { describe, expect, it } from 'vitest';
import { validateSessionEnvelope } from '../../src/tutor/session_envelope';

describe('validateSessionEnvelope', () => {
  it('accepts a guardian-started one-child lesson-bound envelope', () => {
    expect(() => validateSessionEnvelope({
      sessionId: 'sess-1',
      childId: 'child-1',
      guardianId: 'guardian-1',
      lessonId: 'lesson-1',
      mode: 'child',
      startedBy: 'guardian',
      status: 'active'
    })).not.toThrow();
  });

  it('rejects tutoring without lesson binding', () => {
    expect(() => validateSessionEnvelope({
      sessionId: 'sess-2',
      childId: 'child-1',
      guardianId: 'guardian-1',
      mode: 'child',
      startedBy: 'guardian',
      status: 'active'
    } as any)).toThrow(/lesson/i);
  });

  it('rejects non-guardian child sessions', () => {
    expect(() => validateSessionEnvelope({
      sessionId: 'sess-3',
      childId: 'child-1',
      guardianId: 'guardian-1',
      lessonId: 'lesson-1',
      mode: 'child',
      startedBy: 'child',
      status: 'active'
    })).toThrow(/guardian/i);
  });
});

