export interface SessionEnvelope {
  sessionId: string;
  childId: string;
  guardianId: string;
  lessonId: string;
  mode: 'child' | 'guardian_review';
  startedBy: 'guardian';
  status: 'active' | 'paused' | 'ended' | 'escalated';
}

export function validateSessionEnvelope(envelope: SessionEnvelope): SessionEnvelope {
  return envelope;
}
